What does this program print?

```cpp
#include <iostream>
struct Vec {
    int x, y;
};
constexpr Vec scale(Vec v, int factor) {
    return Vec{v.x * factor, v.y * factor};
}
int main() {
    constexpr Vec a{2, 3};
    constexpr Vec b = scale(a, 4);
    std::cout << b.x << " " << b.y << "\n";
}
```

The student wants to verify at compile time that the area of a unit square is 1. The program does not compile. What is the bug?

```cpp
class Square {
public:
    constexpr Square(int side) : m_side{side} {}
    int area() const { return m_side * m_side; }
private:
    int m_side;
};
static_assert(Square{1}.area() == 1, "unit square");
```

Does this compile, and if so what does it print?

```cpp
#include <iostream>
struct Pair {
    int first, second;
};
constexpr Pair swap(Pair p) {
    return Pair{p.second, p.first};
}
int main() {
    constexpr Pair p{10, 20};
    constexpr Pair q = swap(p);
    static_assert(q.first == 20);
    std::cout << q.first << " " << q.second << "\n";
}
```

